import { Router } from "express";
import { authMiddleware } from "../middleware/auth.js";
import { authRoutes } from "./auth.routes.js";
import { dashboardRoutes } from "./dashboard.routes.js";
import { siteRoutes } from "./sites.routes.js";
import { feedRoutes } from "./feeds.routes.js";
import { scheduleRoutes } from "./schedules.routes.js";
import { postRoutes } from "./posts.routes.js";
import { promptRoutes } from "./prompts.routes.js";
import { analyticsRoutes } from "./analytics.routes.js";
import { logRoutes } from "./logs.routes.js";
import { settingsRoutes } from "./settings.routes.js";
import { billingRoutes } from "./billing.routes.js";
import { wordpressRoutes } from "./wordpress.routes.js";
import { socialRoutes } from "./social.routes.js";
export const apiRouter = Router();
apiRouter.get("/health", (_req, res) => {
    res.json({ status: "ok", service: "autonews-api", timestamp: new Date().toISOString() });
});
apiRouter.use("/auth", authRoutes);
apiRouter.use(authMiddleware);
apiRouter.use("/dashboard", dashboardRoutes);
apiRouter.use("/sites", siteRoutes);
apiRouter.use("/feeds", feedRoutes);
apiRouter.use("/schedules", scheduleRoutes);
apiRouter.use("/posts", postRoutes);
apiRouter.use("/prompts", promptRoutes);
apiRouter.use("/analytics", analyticsRoutes);
apiRouter.use("/logs", logRoutes);
apiRouter.use("/settings", settingsRoutes);
apiRouter.use("/billing", billingRoutes);
apiRouter.use("/wordpress", wordpressRoutes);
apiRouter.use("/social", socialRoutes);
